package batch75;

public class wrapperObjects {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		Integer productId=101;
		String productName="printing machine";
		Double productPrice=799.9;
		Float productRating=4.5F;
		Boolean productStatus=true;
		Integer StockQuantity=150;
		Double DiscountPercentage=15.0;
		Character productCode='A';
		
		System.out.println("PRODUCT DETAILS");
		System.out.println("----------------------------");
		System.out.println("product ID:"+productId);
		System.out.println("product Name:"+productName);
		System.out.println("product price:"+productPrice);
		System.out.println("product rating:"+productRating);
		System.out.println("product Status:"+productStatus);
		System.out.println("product Stock Quantity:"+StockQuantity);
		System.out.println("product Discount percentage:"+DiscountPercentage);
		System.out.println("product Code:"+productCode);
	}

}
